import urllib.request, re, html, json

ua={"User-Agent":"Mozilla/5.0"}
url="https://www.remotedxb.com/job/principal-software-engineer-cyberhaven--644406"
req=urllib.request.Request(url, headers=ua)
with urllib.request.urlopen(req, timeout=30) as r:
    text=r.read().decode("utf-8","replace")

# Properly extract data-page attribute (HTML entity encoded JSON)
m=re.search(r'data-page="([^"]*)"', text)
raw=html.unescape(m.group(1))
# sometimes truncated? check start
print("raw starts:", raw[:80])
print("raw ends:", raw[-80:])
print("len raw", len(raw))
try:
    data=json.loads(raw)
except Exception as e:
