        print(f"  {k}: {str(v)[:160]}")

job = props.get("job") or props.get("listing") or props.get("posting")
# search nested
def find_keys(obj, needle, path=""):
    found=[]
    if isinstance(obj, dict):
        for kk,vv in obj.items():
            p=f"{path}.{kk}" if path else kk
            if needle in kk.lower():
                found.append((p, type(vv).__name__, str(vv)[:200]))
            found.extend(find_keys(vv, needle, p))
    elif isinstance(obj, list) and obj and isinstance(obj[0], (dict,list)):
        for i,vv in enumerate(obj[:3]):
            found.extend(find_keys(vv, needle, f"{path}[{i}]"))
    return found

for needle in ["apply","url","company","remote","salary","external","description","location"]:
